import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"崩劫","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/崩劫.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/崩劫.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/崩劫.md"};function l(i,e,_,c,p,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"崩劫",tabindex:"-1"},[n("崩劫 "),a("a",{class:"header-anchor",href:"#崩劫","aria-label":'Permalink to "崩劫"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),o('<h1 id="崩劫-1" tabindex="-1">崩劫 <a class="header-anchor" href="#崩劫-1" aria-label="Permalink to &quot;崩劫&quot;">​</a></h1><p>崩劫<br> 本质：魔幻本质<br> 价格：B+2000<br> 分类：拳套<br> 描述：这对手套是用黑龙的鳞片所制成的，不仅拥有极强的破魔效果，而且戴在手上丝毫没有任何感觉。细碎的鳞片上覆盖着一层结构复杂的合金，只要将手握成拳，拳套就会随着手型的改变而竖立起一层尖锐的倒刺，更添威力。<br> 武器基本属性：双手天生武器进行攻击时提供6个附加成功，威猛5，破魔10<br> 武器特殊属性：【破法】【眩晕】【8加骰】<br> 贯甲：以标准动作进行一次普通攻击或者是以整轮动作进行一次冲锋，这次攻击中获得以下效果：<br> 若对方具有盔甲防御，盾牌防御和天生防御，则武器破甲提升穿戴者传奇力量*5点，对应防御如果被减少到0，则每剩余1点破甲，此次攻击就额外获得1点器械加值。（接触攻击也要如常计算目标的盔甲防御，盾牌防御和天生防御）<br> 追击：攻击拥有“眩晕”不良状态的目标时，在这次攻击检定上获得等于对方所受到的眩晕效果点数的附加成功，上限为武技等级/2。<br> 砸碎（需开启物品破坏规则）：用这对手套攻击非生命的物体时，提升双手的天生武器破甲再提升20点，并且在攻击上获得+10附加成功的加值。<br> （『眩晕』：由于巨大的冲击力，如果伤害超过了对方的体积，超过的每点伤害会同时带来一点晕眩点数，以标准方式减免。）</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',4)])])}const f=r(d,[["render",l]]);export{m as __pageData,f as default};
